    SEQ, RESUME_NO, CPNY_ID, DEPTNO, CODE_NO, IS_DEFAULT, 
    ACTIVITY, ORDERNO, CREATE_DATE, CREATED_BY, CREATED_IP, 
    UPDATE_DATE, UPDATED_BY, UPDATED_IP
) VALUES (
